/**
 * mini-htmx — htmx 의 핵심 기능만 직접 구현한 학습용 셰임.
 *
 * 지원 속성:
 *  - hx-get, hx-post: 클릭/submit/주기 트리거 시 fetch
 *  - hx-trigger: "every 5s" 또는 "load" 또는 (기본) "click"/"submit"
 *  - hx-target: 응답 HTML 을 swap 할 대상 (CSS selector). 미지정이면 자기 자신.
 *  - hx-swap: "innerHTML" (기본) | "outerHTML"
 *  - hx-confirm: confirm() 다이얼로그 메시지
 *  - HX-Redirect 응답 헤더: 받으면 location 변경
 *  - HX-Request 요청 헤더: 항상 "true" 로 송신
 *
 * 실제 htmx 가 제공하는 기능 중 본 셰임이 빠뜨리는 것: out-of-band swap, history,
 * websocket/sse 확장, hx-vals, hx-include, error 이벤트 등. Phase 가 진행되면서
 * 필요해지는 시점에 진짜 htmx 로 교체.
 */
(function () {
  "use strict";

  function $$(selector) { return Array.from(document.querySelectorAll(selector)); }

  function getTarget(el) {
    var sel = el.getAttribute("hx-target");
    if (!sel) return el;
    if (sel === "this") return el;
    return document.querySelector(sel) || el;
  }

  function swap(target, html, mode) {
    if (mode === "outerHTML") {
      target.outerHTML = html;
    } else {
      target.innerHTML = html;
    }
  }

  async function fire(el, method) {
    var url = el.getAttribute("hx-" + method.toLowerCase());
    if (!url) return;
    var confirmMsg = el.getAttribute("hx-confirm");
    if (confirmMsg && !window.confirm(confirmMsg)) return;
    var target = getTarget(el);
    var body = null;
    var headers = { "HX-Request": "true" };
    if (method === "POST" && el.tagName === "FORM") {
      body = new URLSearchParams(new FormData(el)).toString();
      headers["Content-Type"] = "application/x-www-form-urlencoded";
    }
    try {
      var res = await fetch(url, { method: method, body: body, headers: headers, credentials: "same-origin" });
      var redirect = res.headers.get("HX-Redirect");
      if (redirect) { window.location.href = redirect; return; }
      var html = await res.text();
      var mode = el.getAttribute("hx-swap") || "innerHTML";
      swap(target, html, mode);
      // swap 후 새로 들어온 노드에도 트리거 바인딩.
      bindAll(target);
    } catch (err) {
      console.error("[mini-htmx] fetch 실패", err);
    }
  }

  function parseEvery(triggerAttr) {
    if (!triggerAttr) return null;
    var m = triggerAttr.match(/every\s+(\d+)\s*(ms|s|m)?/);
    if (!m) return null;
    var n = parseInt(m[1], 10);
    var unit = m[2] || "s";
    return unit === "ms" ? n : unit === "m" ? n * 60_000 : n * 1000;
  }

  function bind(el) {
    if (el.dataset.miniHtmxBound === "1") return;
    el.dataset.miniHtmxBound = "1";
    var trigger = el.getAttribute("hx-trigger");
    var hasGet = el.hasAttribute("hx-get");
    var hasPost = el.hasAttribute("hx-post");
    if (!hasGet && !hasPost) return;
    var method = hasGet ? "GET" : "POST";

    var everyMs = parseEvery(trigger);
    if (everyMs != null) {
      // 페이지에 있는 동안 주기 폴링. 탭 비활성 상태에서도 그대로 폴링되며,
      // 화면에 보일 때만 갱신하고 싶다면 IntersectionObserver 추가가 자연스러움.
      setInterval(function () { fire(el, method); }, everyMs);
    }
    var triggers = (trigger || "").split(",").map(function (s) { return s.trim(); });
    if (triggers.indexOf("load") >= 0) {
      // 마이크로태스크 다음 turn 에 즉시 1 회 발화.
      setTimeout(function () { fire(el, method); }, 0);
    }

    // 기본 트리거: form 은 submit, 그 외는 click.
    if (el.tagName === "FORM") {
      el.addEventListener("submit", function (e) { e.preventDefault(); fire(el, method); });
    } else if (triggers.indexOf("every") < 0 && triggers.indexOf("load") < 0) {
      el.addEventListener("click", function (e) { e.preventDefault(); fire(el, method); });
    }
  }

  function bindAll(root) {
    var scope = root && root.querySelectorAll ? root : document;
    scope.querySelectorAll("[hx-get],[hx-post]").forEach(bind);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () { bindAll(document); });
  } else {
    bindAll(document);
  }
})();
